mapper.select:
SELECT r.*, u.real_name as ownerName, o.building as ownerBuilding, o.unit as ownerUnit, o.room_number as ownerRoomNumber, ru.real_name as repairerName FROM repair r LEFT JOIN owner o ON r.owner_id = o.id LEFT JOIN sys_user u ON o.user_id = u.id LEFT JOIN sys_user ru ON r.repairer_id = ru.id
AND r.owner_id = #{ownerId}
AND r.repairer_id = #{repairerId}
AND r.status = #{status}
AND (r.title LIKE CONCAT('%', #{keyword}, '%') OR r.description LIKE CONCAT('%', #{keyword}, '%'))
ORDER BY r.create_time DESC
